svg.script:
//
(function () {
  // ============================================================
  // GRADIENT CONFIGURATION
  // Each entry is [topColor, midColor, bottomColor].
  // Call svg.setGradients([...]) at runtime to swap them.
  // ============================================================
  var gradients = [
    ['#5CE1C8', '#A8E06C', '#F5C842'],
    ['#667EEA', '#9B6FD4', '#F093FB'],
    ['#FF6B6B', '#FF8E53', '#FED330'],
    ['#00C9FF', '#44D492', '#92FE9D']
  ];

  var MS_PER_TRANSITION = 4000;
  var grad = document.getElementById('edg-grad');
  var stops = grad.querySelectorAll('stop');
  var svg = document.getElementById('edg-logo') || document.documentElement;

  // Runtime API
  svg.setGradients = function (g) { gradients = g; };
  svg.getGradients = function () { return gradients; };

  function hex2rgb(h) {
    return [
      parseInt(h.slice(1, 3), 16),
      parseInt(h.slice(3, 5), 16),
      parseInt(h.slice(5, 7), 16)
    ];
  }

  function rgb2hex(r, g, b) {
    return '#' + [r, g, b].map(function (v) {
      return Math.round(Math.max(0, Math.min(255, v)))
        .toString(16).padStart(2, '0');
    }).join('');
  }

  function ease(t) {
    return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;
  }

  var t0 = null;

  function frame(ts) {
    if (!t0) t0 = ts;
    var total = gradients.length * MS_PER_TRANSITION;
    var pos = (ts - t0) % total;
    var idx = Math.floor(pos / MS_PER_TRANSITION);
    var t = ease((pos % MS_PER_TRANSITION) / MS_PER_TRANSITION);
    var from = gradients[idx];
    var to = gradients[(idx + 1) % gradients.length];

    for (var i = 0; i < 3; i++) {
      var a = hex2rgb(from[i]), b = hex2rgb(to[i]);
      stops[i].setAttribute('stop-color', rgb2hex(
        a[0] + (b[0] - a[0]) * t,
        a[1] + (b[1] - a[1]) * t,
        a[2] + (b[2] - a[2]) * t
      ));
    }
    requestAnimationFrame(frame);
  }

  // Set initial gradient
  for (var i = 0; i < 3; i++) {
    stops[i].setAttribute('stop-color', gradients[0][i]);
  }

  requestAnimationFrame(frame);
})();
//
